 1→import { onMount, type Accessor } from 'solid-js';
 2→import type { Renderer } from '../renderer/Renderer';
 3→
 4→interface Props {
 5→  label: string;
 6→  type: 'health' | 'mana' | 'xp' | 'build';
 7→  fillPercent: Accessor<number>;
 8→  maxValue?: number;
 9→  height?: number;
10→  hasBorder?: boolean;
11→  renderer: Renderer;
12→}
13→
14→export default function StatBar(props: Props) {
15→  let ref!: HTMLDivElement;
16→
17→  onMount(() => {
18→    props.renderer.statBars.push({
19→      ref: () => ref,
20→      fillPercent: props.fillPercent,
21→      type: props.type,
22→      hasBorder: !!props.hasBorder,
23→    });
24→  });
25→
26→  const barText = () => {
27→    const pct = props.fillPercent();
28→    if (props.type === 'build') return pct + '%';
29→    if (props.maxValue) {
30→      return Math.floor(props.maxValue * pct / 100) + '\u00a0/ ' + props.maxValue;
31→    }
32→    return pct + '%';
33→  };
34→
35→  return (
36→    <div class="bar-row">
37→      <span class="bar-label">{props.label}</span>
38→      <div ref={ref} class="stat-bar" style={{ height: (props.height || 18) + 'px' }}>
39→        <div
40→          class={`bar-fill-img ${props.type}-fill animated-bar`}
41→          style={{ width: props.fillPercent() + '%' }}
42→        />
43→        {props.hasBorder && <img class="bar-border-overlay" src="" alt="" />}
44→        <div class="bar-text" style={props.height && props.height < 18 ? { 'font-size': '0.6rem' } : {}}>
45→          {barText()}
46→        </div>
47→      </div>
48→    </div>
49→  );
50→}
